// Payout for one damage: the reimbursement minus the deductible, never below 0.
const damagePayout = (item: Item, damage: Damage): number =>
  Math.max(0, reimbursement(item, damage) - DEDUCTIBLE);

// The policy item insuring a given damage's type. The non-null assertion
// assumes the type is covered; rejecting damages for uncovered types is a
// separate validation concern (a later test), and isolating the lookup here
// gives that change a single place to act.
const itemFor = (policyItems: Item[], damage: Damage): Item =>
  policyItems.find((item) => item.type === damage.itemType)!;

export const claim = (
  policyItems: Item[],
  incident: Incident,
  remainingCap: number,
): ClaimResult => {
  const requested = sumBy(incident.damages, (damage) =>
    damagePayout(itemFor(policyItems, damage), damage),
  );
  const payout = Math.floor(Math.min(requested, remainingCap));
  return { payout, remainingCap: remainingCap - payout };
};
